func (p *Provider) SessionExist(ctx context.Context, sid string) (bool, error) {
	if p.client == nil {
		if err := p.connectInit(); err != nil {
			return false, err
		}
	}
	value, err := p.client.Get(sid)
	if err != nil {
		panic(err)
	}
	if value == nil || len(value.(string)) == 0 {
		return false, nil
	}
	return true, nil
}
